// Get the response from AWS Lambda
const responseBody = $input.first().json;
console.log('Raw Lambda Response:', JSON.stringify(responseBody, null, 2));

// Helper function to parse native Athena ResultSet row format
function parseAthenaRows(resultSet) {
  if (!resultSet || !resultSet.Rows || resultSet.Rows.length === 0) {
    return [];
  }
  const rows = resultSet.Rows;
  const columnNames = rows[0].Data.map(col => col.VarCharValue);
  return rows.slice(1).map(row => {
    const rowData = {};
    row.Data.forEach((cell, index) => {
      rowData[columnNames[index]] = cell.VarCharValue || null;
    });
    return rowData;
  });
}

let parsedRows = [];

if (responseBody.ResultSet && responseBody.ResultSet.Rows) {
  parsedRows = parseAthenaRows(responseBody.ResultSet);
} else if (responseBody.data && Array.isArray(responseBody.data)) {
  parsedRows = responseBody.data;
} else if (responseBody.result && responseBody.result.body) {
  const body = typeof responseBody.result.body === 'string'
    ? JSON.parse(responseBody.result.body)
    : responseBody.result.body;
  if (body.rows && Array.isArray(body.rows)) parsedRows = body.rows;
  else if (body.ResultSet) parsedRows = parseAthenaRows(body.ResultSet);
  else if (body.data) parsedRows = body.data;
} else if (responseBody.body) {
  const body = typeof responseBody.body === 'string'
    ? JSON.parse(responseBody.body)
    : responseBody.body;
  if (body.ResultSet) parsedRows = parseAthenaRows(body.ResultSet);
  else if (body.data) parsedRows = body.data;
  else if (body.rows) parsedRows = body.rows;
} else if (Array.isArray(responseBody)) {
  parsedRows = responseBody;
}

console.log(`Parsed ${parsedRows.length} rows`);

if (parsedRows.length === 0) {
  return [{ json: { rowCount: 0, message: 'No new star hosts detected' } }];
}

return parsedRows.map((row, index) => ({
  json: {
    ...row,
    rowCount: parsedRows.length,
    activity_subject: 'Star Host: Pitch Referral',
    _debug_row_index: index + 1
  }
}));

// Pull the deal owner straight from Pipedrive (live), not from Athena.
const hostData = $('Process Each Star Host One-by-One').item.json;
const dealResponse = $input.first().json;

const ownerId = dealResponse.data?.owner_id?.id || dealResponse.data?.user_id?.id || null;

return {
  json: {
    ...hostData,
    owner_id: ownerId
  }
};

// Dedup guard for this deal. Skip creating the activity if EITHER check matches.
//   Check 1 (existing, UNCHANGED): a "Star Host: Pitch Referral" activity already exists on the deal.
//   Check 2 (new): the deal has a DONE "Referral reminder" completed within the last 6 months
//                  (the "Referred Apartment(s) Published: Pitch Referral" subject is exempt and never
//                   blocks; a not-done "Referral reminder" never blocks via this check).
const hostData = $('Process Each Star Host One-by-One').item.json;
const ownerId = $('Extract Deal Owner').item.json.owner_id;
const expectedSubject = 'Star Host: Pitch Referral';
const dealId = hostData.deal_id;

const activitiesResponse = $input.first().json;
const allActivities = activitiesResponse.data || [];

let debugInfo = {
  checking_deal: dealId,
  expected_subject: expectedSubject,
  total_activities_checked: allActivities.length,
  duplicate_found: false,
  should_skip: false
};

// --- Check 1 (existing logic, UNCHANGED): same-subject activity already on the deal ---
const matchingActivities = allActivities.filter(activity => {
  if (!activity.subject) return false;
  return activity.subject === expectedSubject;
});
debugInfo.matching_activities_found = matchingActivities.length;
const existingDuplicate = matchingActivities.length > 0;

// --- Check 2 (new): done "Referral reminder" completed within the last 6 months ---
const EXEMPT_SUBJECT = 'Referred Apartment(s) Published: Pitch Referral';
const normType = t => String(t || '').trim().toLowerCase().replace(/[\s_]+/g, '_');
const sixMonthsAgo = new Date();
sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
const doneReferralReminder = allActivities.some(a => {
  if (normType(a.type) !== 'referral_reminder') return false;        // must be a Referral reminder
  if (a.done !== true) return false;                                 // must be marked done
  if (a.subject && a.subject.trim() === EXEMPT_SUBJECT) return false; // exempt subject never blocks
  if (!a.marked_as_done_time) return false;                          // need a completion timestamp
  return new Date(a.marked_as_done_time) >= sixMonthsAgo;            // marked done within last 6 months
});

debugInfo.check1_existing_duplicate = existingDuplicate;
debugInfo.check2_done_referral_reminder = doneReferralReminder;

// --- Final flag: skip if EITHER check matched ---
const shouldSkip = existingDuplicate || doneReferralReminder;
debugInfo.duplicate_found = shouldSkip;
debugInfo.should_skip = shouldSkip;

if (shouldSkip) {
  const reasons = [];
  if (existingDuplicate) reasons.push('Check 1: a "Star Host: Pitch Referral" activity already exists on this deal');
  if (doneReferralReminder) reasons.push('Check 2: a done "Referral reminder" was completed within the last 6 months');
  debugInfo.action = 'SKIPPING - ' + reasons.join(' AND ');
  debugInfo._duplicate_check = 'SKIP (' + reasons.join(' | ') + ')';
  return { json: { ...hostData, owner_id: ownerId, _debug: debugInfo, _skip: true } };
}

debugInfo.action = 'PROCEEDING - passed Check 1 (no same-subject activity) and Check 2 (no recent done referral reminder)';
debugInfo._duplicate_check = 'PROCEED: Check 1 (own subject) + Check 2 (done referral reminder within 6 months) both clear';
return { json: { ...hostData, owner_id: ownerId, _debug: debugInfo, _skip: false } };

// Normalize the Pipedrive REST response into a clean success/error shape.
const response = $input.first().json;

return {
  json: {
    success: response.success || false,
    activity_id: response.data?.id || null,
    error: response.error || null,
    original_response: response
  }
};

