// Reset the empty-run counter whenever Athena returns candidates.
const sd = $getWorkflowStaticData('global');
sd.zeroStreak = 0;
sd.lastNonZero = new Date().toISOString().slice(0, 10);
return $input.all();

// Count consecutive runs where Athena returned 0 candidates; emit an item only past the threshold.
const sd = $getWorkflowStaticData('global');
sd.zeroStreak = (sd.zeroStreak || 0) + 1;
const N = 3; // alert after this many empty runs in a row
if (sd.zeroStreak >= N) {
  return [{ json: { zeroStreak: sd.zeroStreak, threshold: N, lastNonZero: sd.lastNonZero || 'unknown' } }];
}
return [];

